"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["3234"],{6352(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/es/blog/welcome","source":"@site/i18n/es/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Bienvenido a la Wiki de Heiman Technology","description":"\xa1Bienvenido a la Wiki de Heiman Technology! Esta es la base de conocimiento oficial que re\xfane documentaci\xf3n de productos, soluciones t\xe9cnicas, noticias de la industria y actualizaciones de la empresa.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/es/blog/tags/heiman","description":"Noticias y actualizaciones de Heiman Technology"}],"readingTime":0.75,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/es/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Bienvenido a la Wiki de Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Detector de Humo Inteligente Matter de Heiman Lanzado Oficialmente","permalink":"/heiman-wiki-public/es/blog/mdx-blog-post"}},"content":"\xa1Bienvenido a la Wiki de Heiman Technology! Esta es la base de conocimiento oficial que re\xfane documentaci\xf3n de productos, soluciones t\xe9cnicas, noticias de la industria y actualizaciones de la empresa.\\n\\n{/* truncate */}\\n\\n## Acerca de Este Sitio\\n\\nLa Wiki de Heiman Technology est\xe1 dedicada a proporcionar un recurso t\xe9cnico integral para socios, desarrolladores y clientes:\\n\\n- **Productos** \u2014 Seguridad contra Incendios Inteligente, Seguridad de Gas Inteligente, Cuidado de Ancianos Inteligente, Sensores Inteligentes\\n- **Soluciones** \u2014 Soluciones de seguridad inteligente a nivel industrial\\n- **Documentos T\xe9cnicos** \u2014 Gu\xedas de integraci\xf3n de API, uso de SDK, manuales de instalaci\xf3n\\n- **Perspectivas de la Industria** \u2014 Tendencias de seguridad inteligente y an\xe1lisis normativo\\n\\n## Navegaci\xf3n R\xe1pida\\n\\n- Explore [Productos y Soluciones](/docs/tutorial-basics/create-a-page)\\n- Lea [Sobre Nosotros](/docs/intro) para conocer la historia de Heiman\\n- Visite el [Sitio Oficial de Heiman](https://www.heiman.com.cn)\\n\\nPara cualquier pregunta, llame a nuestra l\xednea directa **400-8959-500** o comun\xedquese con el soporte en l\xednea."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/es/blog/mdx-blog-post","source":"@site/i18n/es/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Detector de Humo Inteligente Matter de Heiman Lanzado Oficialmente","description":"El detector de humo inteligente de nueva generaci\xf3n con protocolo Matter de Heiman Technology, el HS1SA-M, ha sido lanzado oficialmente \u2014 uno de los primeros detectores de humo de la industria en recibir la certificaci\xf3n Matter 1.2.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/es/blog/tags/matter","description":"Contenido relacionado con el protocolo Matter"},{"inline":false,"label":"Seguridad contra Incendios Inteligente","permalink":"/heiman-wiki-public/es/blog/tags/smart-fire","description":"Productos y soluciones de seguridad contra incendios inteligente"}],"readingTime":0.8,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/es/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Detector de Humo Inteligente Matter de Heiman Lanzado Oficialmente","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Bienvenido a la Wiki de Heiman Technology","permalink":"/heiman-wiki-public/es/blog/welcome"},"nextItem":{"title":"Hitos de Heiman Technology","permalink":"/heiman-wiki-public/es/blog/long-blog-post"}},"content":"El detector de humo inteligente de nueva generaci\xf3n con protocolo Matter de Heiman Technology, el HS1SA-M, ha sido lanzado oficialmente \u2014 uno de los primeros detectores de humo de la industria en recibir la certificaci\xf3n Matter 1.2.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nEl HS1SA-M es compatible con Apple HomeKit, Amazon Alexa, Google Home y Samsung SmartThings \u2014 los cuatro principales ecosistemas de hogar inteligente.\\n\\n:::\\n\\n## Caracter\xedsticas Clave\\n\\n- **Certificado Matter 1.2** \u2014 Interoperabilidad entre marcas y ecosistemas\\n- **Detecci\xf3n de Humo Fotoel\xe9ctrica** \u2014 Respuesta r\xe1pida a varios tipos de humo de incendio\\n- **Alarma de Voz** \u2014 M\xfaltiples opciones de idioma, alertas de peligro claras\\n- **Funci\xf3n de Autocomprobaci\xf3n** \u2014 Autoverificaciones regulares para garantizar el funcionamiento normal\\n- **Notificaci\xf3n Remota** \u2014 Alertas push en tiempo real a la aplicaci\xf3n de su tel\xe9fono\\n\\n## Compatibilidad\\n\\nEl HS1SA-M se integra perfectamente con las principales plataformas de hogar inteligente sin necesidad de un gateway adicional \u2014 gestione todo directamente desde su tel\xe9fono.\\n\\nVisite la p\xe1gina de [Productos](/docs/tutorial-basics/create-a-page) para obtener m\xe1s informaci\xf3n."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/es/blog/long-blog-post","source":"@site/i18n/es/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Hitos de Heiman Technology","description":"Desde su fundaci\xf3n en 2005, Heiman Technology ha recorrido m\xe1s de 20 a\xf1os. Este art\xedculo repasa los hitos clave de Heiman.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/es/blog/tags/heiman","description":"Noticias y actualizaciones de Heiman Technology"}],"readingTime":1.36,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/es/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Hitos de Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Detector de Humo Inteligente Matter de Heiman Lanzado Oficialmente","permalink":"/heiman-wiki-public/es/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology Reconocida como Empresa Nacional \\"Little Giant\\"","permalink":"/heiman-wiki-public/es/blog/first-blog-post"}},"content":"Desde su fundaci\xf3n en 2005, Heiman Technology ha recorrido m\xe1s de 20 a\xf1os. Este art\xedculo repasa los hitos clave de Heiman.\\n\\n{/* truncate */}\\n\\n## 2005 - Fundaci\xf3n de la Empresa\\n\\nSe estableci\xf3 oficialmente Shenzhen Heiman Technology Co., Ltd., ingresando al campo de los sensores de seguridad.\\n\\n## 2006 - Inicio Internacional\\n\\nM\xfaltiples productos obtuvieron la certificaci\xf3n CE de la UE y se asociaron con China Mobile.\\n\\n## 2011 - Avance en Certificaci\xf3n Internacional\\n\\nM\xfaltiples productos obtuvieron las certificaciones EN54-7 y EN14604 de la UE, alcanzando est\xe1ndares internacionales de calidad.\\n\\n## 2012 - Transformaci\xf3n hacia Hogar Inteligente\\n\\nEl proyecto de hogar inteligente se lanz\xf3 por completo, transformando a Heiman en una empresa especializada en I+D, producci\xf3n y venta de productos para el hogar inteligente.\\n\\n## 2017 - Grandes Avances\\n\\n- Desarroll\xf3 la primera alarma de humo NB-IoT de China\\n- Gan\xf3 2 Premios Red Dot de Dise\xf1o\\n- Obtuvo la certificaci\xf3n MFi, calificando como fabricante de Apple\\n\\n## 2020 - Impulso de Capital\\n\\nComplet\xf3 la financiaci\xf3n de la Serie A con el Grupo Shenzhen\u9AD8\u65B0\u6295, reconocida como \\"PYME Especializada y Nueva de la Provincia de Guangdong\\".\\n\\n## 2022 - Reconocimiento Nacional\\n\\nReconocida como Empresa Nacional Especializada y Nueva \\"Little Giant\\". La serie K1 gan\xf3 el Premio Red Dot de Dise\xf1o.\\n\\n## 2023 - Liderazgo en Est\xe1ndares Internacionales\\n\\nEl laboratorio de pruebas de Heiman obtuvo oficialmente la certificaci\xf3n CNAS. Los detectores de humo y alarmas de CO fueron de los primeros en obtener la certificaci\xf3n Matter 1.2.\\n\\n## 2024 - Presente\\n\\nContinuando con la innovaci\xf3n, profundizando el compromiso con Seguridad contra Incendios Inteligente, Seguridad de Gas Inteligente, Cuidado de Ancianos Inteligente y Sensores Inteligentes, proporcionando productos y servicios de calidad a clientes en m\xe1s de 100 pa\xedses en todo el mundo."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/es/blog/first-blog-post","source":"@site/i18n/es/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology Reconocida como Empresa Nacional \\"Little Giant\\"","description":"En 2022, Heiman Technology fue reconocida oficialmente como Empresa Nacional Especializada y Nueva \\"Little Giant\\" por su profunda acumulaci\xf3n t\xe9cnica e innovaci\xf3n en el campo de los sensores inteligentes.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/es/blog/tags/heiman","description":"Noticias y actualizaciones de Heiman Technology"}],"readingTime":0.5,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/es/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology Reconocida como Empresa Nacional \\"Little Giant\\"","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Hitos de Heiman Technology","permalink":"/heiman-wiki-public/es/blog/long-blog-post"}},"content":"En 2022, Heiman Technology fue reconocida oficialmente como Empresa Nacional Especializada y Nueva \\"Little Giant\\" por su profunda acumulaci\xf3n t\xe9cnica e innovaci\xf3n en el campo de los sensores inteligentes.\\n\\n{/* truncate */}\\n\\nEste reconocimiento a nivel nacional afirma la excelencia de Heiman en especializaci\xf3n, refinamiento, diferenciaci\xf3n e innovaci\xf3n. Heiman continuar\xe1 profundizando sus esfuerzos en Seguridad contra Incendios Inteligente, Seguridad de Gas Inteligente, Cuidado de Ancianos Inteligente y Sensores Inteligentes, ofreciendo constantemente productos y servicios de alta calidad a los clientes.\\n\\nHeiman hab\xeda recibido previamente reconocimiento como Empresa Nacional de Alta Tecnolog\xeda y como PYME Especializada y Nueva de la Provincia de Guangdong."}]}}')}}]);